            UPDATE public.utm_visualization
      SET aggregation= $$
{
  "metrics": [
    {
      "id": "1",
      "aggregation": "COUNT",
      "field": "",
      "customLabel": ""
    }
  ],
  "bucket": {
    "id": "1000",
    "aggregation": "TERMS",
    "type": "BUCKET",
    "field": "action.keyword",
    "customLabel": "Operation",
    "subBucket": {
      "id": "1001",
      "aggregation": "TERMS",
      "type": "BUCKET",
      "field": "log.Workload.keyword",
      "customLabel": "workload",
      "subBucket": {
        "id": "1002",
        "aggregation": "TERMS",
        "type": "BUCKET",
        "field": "actionResult.keyword",
        "customLabel": "Result status",
        "subBucket": {
          "id": "1003",
          "aggregation": "TERMS",
          "type": "BUCKET",
          "field": "origin.user.keyword",
          "customLabel": "User",
          "subBucket": {
            "id": "1004",
            "aggregation": "TERMS",
            "type": "BUCKET",
            "field": "origin.ip.keyword",
            "customLabel": "Client IP",
            "subBucket": {
