          "terms": {
            "sortBy": "_count",
            "asc": false,
            "size": 5
          }
        },
        "terms": {
          "sortBy": "_count",
          "asc": false,
          "size": 5
        }
      },
      "terms": {
        "sortBy": "_count",
        "asc": false,
        "size": 5
      }
    },
    "terms": {
      "sortBy": "_count",
      "asc": false,
      "size": 5
    }
  }
}
      $$
            WHERE id = 562;
